    }
  ],
  "ยาและชีวเวชภัณฑ์": [
    {
      "หัวข้อ": "ตัวอย่างหัวข้อข่าวยาและชีวเวชภัณฑ์",
      "เนื้อหาสำคัญ": "ตัวอย่างเนื้อหาสำคัญของข่าวยาและชีวเวชภัณฑ์"
