    {
      "หัวข้อ": "ตัวอย่างหัวข้อข่าวสินค้าอุปโภคบริโภค",
      "เนื้อหาสำคัญ": "ตัวอย่างเนื้อหาสำคัญของข่าวสินค้าอุปโภคบริโภค"
    }
  ],
  "การเงิน": [
    {
      "หัวข้อ": "ตัวอย่างหัวข้อข่าวการเงิน",
      "เนื้อหาสำคัญ": "ตัวอย่างเนื้อหาสำคัญของข่าวการเงิน"
    }
  ],
  "พลังงาน": [
    {
      "หัวข้อ": "ตัวอย่างหัวข้อข่าวพลังงาน",
      "เนื้อหาสำคัญ": "ตัวอย่างเนื้อหาสำคัญของข่าวพลังงาน"
    }
  ],
  "อุตสาหกรรม": [
    {
      "หัวข้อ": "ตัวอย่างหัวข้อข่าวอุตสาหกรรม",
      "เนื้อหาสำคัญ": "ตัวอย่างเนื้อหาสำคัญของข่าวอุตสาหกรรม"
