parameters.jsCode:
const data = $json.output;

// ดึง URL จาก Tavily results ของ node แรก
const tavilyResults = $('HTTP Request').first().json.results || [];
const urlList = tavilyResults.map(r => r.url).filter(Boolean);

const grouped = {};
let urlIndex = 0;

for (const category in data) {
  if (!grouped[category]) grouped[category] = [];
  for (const news of data[category]) {
    grouped[category].push({
      "หัวข้อ":        news["หัวข้อ"],
      "เนื้อหาสำคัญ": news["เนื้อหาสำคัญ"],
      "url":           urlList[urlIndex % urlList.length] || ""
    });
    urlIndex++;
  }
}

return [{ json: { news: grouped } }];
